export interface Teaching {
  id: string;
  letter: string;
  content: string;
}

export interface Chapter {
  title: string;
  part1: Teaching[];
  part2: Teaching[];
  isIntroduction?: boolean;
}

export interface BookData {
  chapters: Chapter[];
}

export enum ViewMode {
  READING = 'READING',
  SEARCH = 'SEARCH',
  BOOKMARKS = 'BOOKMARKS',
  HOME = 'HOME'
}

import { BookData, Chapter, Teaching } from '../types';
import { RAW_TEXT } from '../constants';

export const parseText = (): BookData => {
  const chapters: Chapter[] = [];

  // Split raw text by chapters roughly based on double newlines and headings
  // This logic is specific to the provided text format
  const lines = RAW_TEXT.split('\n').map(line => line.trim()).filter(line => line.length > 0);

  let currentChapter: Chapter | null = null;
  let currentPart: 'part1' | 'part2' = 'part1';
  let teachingBuffer: string = '';
  let currentLetter: string = '';

  const saveCurrentTeaching = () => {
    if (currentChapter && teachingBuffer && currentLetter) {
        const teaching: Teaching = {
            id: `${currentChapter.title}-${currentPart}-${currentLetter}`,
            letter: currentLetter,
            content: teachingBuffer
        };
        if (currentPart === 'part1') {
            currentChapter.part1.push(teaching);
        } else {
            currentChapter.part2.push(teaching);
        }
        teachingBuffer = '';
        currentLetter = '';
    }
  };

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // Detect Introductions (Special Cases)
    if (line.includes('הקדמה')) {
        if (currentChapter) {
            saveCurrentTeaching();
            chapters.push(currentChapter);
        }
        currentChapter = {
            title: line,
            part1: [],
            part2: [],
            isIntroduction: true
        };
        currentPart = 'part1';
        continue;
    }

    // Detect Parts
    if (line === 'חלק ראשון') {
        saveCurrentTeaching();
        currentPart = 'part1';
        continue;
    }
    if (line === 'חלק שני') {
        saveCurrentTeaching();
        currentPart = 'part2';
        continue;
    }

    // Detect Hebrew Letter Numbering (e.g., "א. ", "ב. ")
    // Regex matches a Hebrew letter followed by a dot at the start of the line
    const letterMatch = line.match(/^([א-ת]{1,3})(\.|\')\s/);

    if (letterMatch) {
        saveCurrentTeaching(); // Save previous
        currentLetter = letterMatch[1];
        teachingBuffer = line.replace(letterMatch[0], ''); // Remove the letter prefix from content
    } else {
        // If it's not a numbered line, check if it's a Chapter Title or continuation text
        // If we are in an introduction, it's just text
        if (currentChapter?.isIntroduction) {
             if (currentChapter.part1.length === 0) {
                 // Create a dummy teaching for the intro text block
                 currentChapter.part1.push({ id: `intro-${currentChapter.title}`, letter: '', content: ''});
             }
             currentChapter.part1[0].content += (currentChapter.part1[0].content ? '\n\n' : '') + line;
        } 
        // If it looks like a title (short, no punctuation at end usually, but hard to guess strictly)
        // We assume titles don't start with numbers and we aren't "inside" a teaching buffer yet if it's a new chapter
        else if (!currentChapter || (teachingBuffer === '' && !letterMatch)) {
             if (currentChapter) {
                saveCurrentTeaching();
                chapters.push(currentChapter);
            }
            currentChapter = {
                title: line,
                part1: [],
                part2: []
            };
            currentPart = 'part1';
        } else {
            // Continuation of previous teaching
            teachingBuffer += ' ' + line;
        }
    }
  }

  // Save last bit
  if (currentChapter) {
      saveCurrentTeaching();
      chapters.push(currentChapter);
  }

  return { chapters };
};

import React from 'react';
import { Book, Menu, X } from 'lucide-react';
import { Chapter } from '../types';

