import React, { useState } from 'react';
import { Chapter, Teaching } from '../types';
import { Bookmark, Copy, Share2 } from 'lucide-react';

interface MiddahViewProps {
  chapter: Chapter;
  bookmarks: string[];
  toggleBookmark: (id: string) => void;
}

const MiddahView: React.FC<MiddahViewProps> = ({ chapter, bookmarks, toggleBookmark }) => {
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopyFeedback(id);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  const renderSection = (title: string, teachings: Teaching[]) => {
    if (!teachings || teachings.length === 0) return null;

    return (
      <div className="mb-12">
        <div className="flex items-center justify-center mb-8">
          <div className="h-px bg-gold/30 flex-1 max-w-xs"></div>
          <h3 className="mx-4 font-display text-2xl text-gold-dark font-bold">{title}</h3>
          <div className="h-px bg-gold/30 flex-1 max-w-xs"></div>
        </div>

        <div className="space-y-6">
          {teachings.map((teaching) => (
            <div 
              key={teaching.id} 
              id={teaching.id}
              className={`
                group relative bg-white p-6 rounded-lg shadow-sm border border-transparent hover:border-gold/30 transition-all duration-300
                ${bookmarks.includes(teaching.id) ? 'ring-1 ring-gold bg-amber-50/50' : ''}
              `}
            >
              <div className="flex gap-4">
                <span className="font-display text-2xl text-gold-dark w-8 shrink-0">{teaching.letter}.</span>
                <p className="font-serif text-xl leading-relaxed text-ink/90 flex-1">
                  {teaching.content}
                </p>
              </div>

              {/* Action Buttons */}
              <div className="absolute top-4 left-4 opacity-0 group-hover:opacity-100 transition-opacity flex gap-2">
                <button 
                  onClick={() => toggleBookmark(teaching.id)}
                  className={`p-1.5 rounded-full hover:bg-gray-100 transition-colors ${bookmarks.includes(teaching.id) ? 'text-gold' : 'text-gray-400'}`}
                  title="שמור ציטוט"
                >
                  <Bookmark size={18} fill={bookmarks.includes(teaching.id) ? "currentColor" : "none"} />
                </button>
                <button 
                  onClick={() => handleCopy(teaching.content, teaching.id)}
                  className="p-1.5 rounded-full hover:bg-gray-100 text-gray-400 hover:text-ink transition-colors relative"
                  title="העתק"
                >
                  {copyFeedback === teaching.id ? (
                    <span className="text-xs font-sans text-green-600 font-bold">הועתק!</span>
                  ) : (
                    <Copy size={18} />
                  )}
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-4xl mx-auto py-8 px-4 md:px-8">
      <header className="text-center mb-12">
        <h1 className="font-display text-5xl md:text-6xl text-ink font-bold mb-4">{chapter.title}</h1>
        {!chapter.isIntroduction && (
          <div className="w-24 h-1 bg-gold mx-auto rounded-full"></div>
        )}
      </header>

      {chapter.isIntroduction ? (
        <article className="prose prose-xl prose-stone max-w-none font-serif leading-relaxed text-justify">
           {chapter.part1.map(t => (
               <p key={t.id} className="whitespace-pre-line mb-6">{t.content}</p>
           ))}
        </article>
      ) : (
        <>
          {renderSection('חלק ראשון', chapter.part1)}
          {renderSection('חלק שני', chapter.part2)}
        </>
      )}
    </div>
  );
};

export default MiddahView;

import React, { useMemo } from 'react';
import { BookData, Teaching } from '../types';
import { Sparkles, BookOpen } from 'lucide-react';

interface WelcomeProps {
  data: BookData;
  onStart: () => void;
}

const Welcome: React.FC<WelcomeProps> = ({ data, onStart }) => {

  const randomTeaching = useMemo(() => {
    const allTeachings: { t: Teaching, title: string }[] = [];
    data.chapters.forEach(c => {
      if (c.isIntroduction) return;
      c.part1.forEach(t => allTeachings.push({ t, title: c.title }));
      c.part2.forEach(t => allTeachings.push({ t, title: c.title }));
    });

    if (allTeachings.length === 0) return null;
    return allTeachings[Math.floor(Math.random() * allTeachings.length)];
  }, [data]);

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh] text-center p-6">
      <div className="mb-8 text-gold-dark animate-pulse">
        <BookOpen size={64} strokeWidth={1} />
      </div>

      <h1 className="font-display text-6xl md:text-8xl text-ink mb-2">ספר המידות</h1>
      <h2 className="font-serif text-2xl text-gray-500 mb-12">רבי נחמן מברסלב</h2>

      {randomTeaching && (
        <div className="max-w-2xl bg-white p-8 rounded-xl shadow-lg border-t-4 border-gold mb-12 transform hover:scale-105 transition-transform duration-300">
          <div className="flex items-center justify-center gap-2 mb-4 text-gold">
            <Sparkles size={16} />
            <span className="font-sans text-sm font-bold tracking-wider">אמרה יומית</span>
            <Sparkles size={16} />
          </div>
          <blockquote className="font-serif text-2xl text-ink/90 leading-relaxed mb-6">
            "{randomTeaching.t.content}"
          </blockquote>
          <cite className="font-display text-xl text-gray-500 not-italic">
            {randomTeaching.title}
          </cite>
        </div>
      )}

      <button
        onClick={onStart}
        className="bg-ink text-paper px-8 py-3 rounded-full font-sans font-bold text-lg hover:bg-gold-dark hover:text-white transition-all duration-300 shadow-md hover:shadow-xl flex items-center gap-2"
      >
        <BookOpen size={20} />
        התחל ללמוד
      </button>
    </div>
  );
};

export default Welcome;

import React, { useState, useMemo } from 'react';
import { BookData, Chapter } from '../types';
import { Search as SearchIcon } from 'lucide-react';

interface SearchProps {
  data: BookData;
  onNavigate: (chapter: Chapter) => void;
}

const Search: React.FC<SearchProps> = ({ data, onNavigate }) => {
  const [query, setQuery] = useState('');

  const results = useMemo(() => {
    if (!query || query.length < 2) return [];

    const res: { chapter: Chapter, content: string, part: string, id: string }[] = [];

    data.chapters.forEach(chapter => {
      // Search in title
      if (chapter.title.includes(query)) {
        res.push({ 
            chapter, 
            content: `פרק: ${chapter.title}`, 
            part: 'כותרת', 
            id: `title-${chapter.title}` 
        });
      }

      // Search in Part 1
      chapter.part1.forEach(t => {
        if (t.content.includes(query)) {
          res.push({ chapter, content: t.content, part: 'חלק ראשון', id: t.id });
        }
      });

      // Search in Part 2
      chapter.part2.forEach(t => {
        if (t.content.includes(query)) {
          res.push({ chapter, content: t.content, part: 'חלק שני', id: t.id });
        }
      });
    });

    return res;
  }, [query, data]);

  const highlightText = (text: string, highlight: string) => {
    const parts = text.split(new RegExp(`(${highlight})`, 'gi'));
    return (
      <span>
        {parts.map((part, i) => 
          part === highlight ? <span key={i} className="bg-gold/40 font-bold">{part}</span> : part
        )}
      </span>
    );
  };

  return (
    <div className="max-w-4xl mx-auto py-8 px-4">
      <div className="relative mb-8">
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="חפש נושא, מילה או משפט..."
          className="w-full p-4 pr-12 rounded-xl border-2 border-gold/30 focus:border-gold outline-none font-sans text-lg shadow-sm bg-white"
          autoFocus
        />
        <SearchIcon className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400" size={24} />
      </div>

      <div className="space-y-4">
        {query.length > 1 && results.length === 0 && (
          <p className="text-center text-gray-500 font-sans mt-8">לא נמצאו תוצאות עבור "{query}"</p>
        )}

        {results.map((result) => (
          <div 
            key={result.id}
            onClick={() => onNavigate(result.chapter)}
            className="bg-white p-4 rounded-lg shadow-sm border border-transparent hover:border-gold/30 cursor-pointer transition-all hover:bg-amber-50/30"
          >
            <div className="flex justify-between items-center mb-2">
              <h3 className="font-display text-xl font-bold text-ink">{result.chapter.title}</h3>
              <span className="text-xs font-sans text-gold-dark bg-gold/10 px-2 py-1 rounded-full">
                {result.part}
              </span>
            </div>
            <p className="font-serif text-lg text-gray-700 leading-relaxed truncate">
              {highlightText(result.content, query)}
            </p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Search;

import React, { useState, useEffect, useMemo } from 'react';
import { Menu, Search as SearchIcon, Home, Book } from 'lucide-react';
import Sidebar from './components/Sidebar';
import MiddahView from './components/MiddahView';
import Welcome from './components/Welcome';
import Search from './components/Search';
import { parseText } from './services/textParser';
import { BookData, Chapter, ViewMode } from './types';

const App: React.FC = () => {
  const [data, setData] = useState<BookData | null>(null);
  const [currentChapter, setCurrentChapter] = useState<Chapter | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.HOME);
  const [bookmarks, setBookmarks] = useState<string[]>([]);

  useEffect(() => {
    // Parse text on mount
    const parsedData = parseText();
    setData(parsedData);

    // Load bookmarks from local storage
    const savedBookmarks = localStorage.getItem('seferBookmarks');
    if (savedBookmarks) {
      setBookmarks(JSON.parse(savedBookmarks));
    }
  }, []);

  const toggleBookmark = (id: string) => {
    const newBookmarks = bookmarks.includes(id)
      ? bookmarks.filter(b => b !== id)
      : [...bookmarks, id];
    setBookmarks(newBookmarks);
    localStorage.setItem('seferBookmarks', JSON.stringify(newBookmarks));
  };

  const handleChapterSelect = (chapter: Chapter) => {
    setCurrentChapter(chapter);
    setViewMode(ViewMode.READING);
    setSidebarOpen(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const mainContent = useMemo(() => {
    if (!data) return <div className="flex justify-center items-center h-full">טוען...</div>;

    switch (viewMode) {
      case ViewMode.HOME:
        return <Welcome data={data} onStart={() => setSidebarOpen(true)} />;
      case ViewMode.SEARCH:
        return <Search data={data} onNavigate={handleChapterSelect} />;
      case ViewMode.READING:
        if (currentChapter) {
          return <MiddahView chapter={currentChapter} bookmarks={bookmarks} toggleBookmark={toggleBookmark} />;
        }
        return <Welcome data={data} onStart={() => setSidebarOpen(true)} />; // Fallback
      default:
        return null;
    }
  }, [viewMode, data, currentChapter, bookmarks]);

  if (!data) return null;

  return (
    <div className="flex h-screen bg-paper overflow-hidden">

      {/* Sidebar */}
      <Sidebar 
        chapters={data.chapters}
        currentChapter={currentChapter}
        onSelectChapter={handleChapterSelect}
        isOpen={sidebarOpen}
        onClose={() => setSidebarOpen(false)}
      />

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0">

        {/* Top Bar */}
        <header className="h-16 bg-paper-dark border-b border-gold/30 flex items-center justify-between px-4 md:px-8 shadow-sm z-30">
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setSidebarOpen(true)}
              className="md:hidden text-ink hover:text-gold-dark p-2"
            >
              <Menu size={24} />
            </button>
            <span className="font-display text-2xl font-bold text-ink hidden md:block">ספר המידות</span>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setViewMode(ViewMode.HOME)}
              className={`p-2 rounded-full transition-colors ${viewMode === ViewMode.HOME ? 'text-gold-dark bg-gold/10' : 'text-gray-500 hover:bg-black/5'}`}
              title="דף הבית"
            >
              <Home size={20} />
            </button>
            <button 
              onClick={() => setViewMode(ViewMode.SEARCH)}
              className={`p-2 rounded-full transition-colors ${viewMode === ViewMode.SEARCH ? 'text-gold-dark bg-gold/10' : 'text-gray-500 hover:bg-black/5'}`}
              title="חיפוש"
            >
              <SearchIcon size={20} />
            </button>
          </div>
        </header>

        {/* Scrollable Content */}
        <main className="flex-1 overflow-y-auto relative scroll-smooth">
          {mainContent}
        </main>

      </div>
    </div>
  );
};

export default App;

export interface Teaching {
  id: string;
  letter: string;
  content: string;
}

export interface Chapter {
  title: string;
  part1: Teaching[];
  part2: Teaching[];
  isIntroduction?: boolean;
}

export interface BookData {
  chapters: Chapter[];
}

export interface Highlight {
  id: string;
  teachingId: string;
  text: string;
  date: number;
}

export enum ViewMode {
  READING = 'READING',
  SEARCH = 'SEARCH',
  BOOKMARKS = 'BOOKMARKS',
  HOME = 'HOME',
  RANDOM = 'RANDOM'
}

import React from 'react';
import { BookData, Chapter, Teaching, Highlight } from '../types';
import { Bookmark, Highlighter, ArrowLeft } from 'lucide-react';

interface BookmarksViewProps {
  data: BookData;
  bookmarks: string[];
  highlights: Highlight[];
  onNavigate: (chapter: Chapter, teachingId?: string) => void;
  onRemoveBookmark: (id: string) => void;
  onRemoveHighlight: (id: string) => void;
}

const BookmarksView: React.FC<BookmarksViewProps> = ({ 
  data, 
  bookmarks, 
  highlights, 
  onNavigate,
  onRemoveBookmark,
  onRemoveHighlight
}) => {

  // Helper to find teaching and chapter details
  const findTeachingDetails = (teachingId: string) => {
    for (const chapter of data.chapters) {
      const t1 = chapter.part1.find(t => t.id === teachingId);
      if (t1) return { chapter, teaching: t1, part: 'חלק ראשון' };
      const t2 = chapter.part2.find(t => t.id === teachingId);
      if (t2) return { chapter, teaching: t2, part: 'חלק שני' };
    }
    return null;
  };

  const savedTeachings = bookmarks
    .map(id => {
      const details = findTeachingDetails(id);
      if (!details) return null;
      return { id, ...details };
    })
    .filter(Boolean) as { id: string, chapter: Chapter, teaching: Teaching, part: string }[];

  const savedHighlights = highlights
    .map(h => {
      const details = findTeachingDetails(h.teachingId);
      if (!details) return null;
      return { highlight: h, ...details };
    })
    .filter(Boolean) as { highlight: Highlight, chapter: Chapter, teaching: Teaching, part: string }[];

  return (
    <div className="max-w-4xl mx-auto py-8 px-4">
      <h1 className="font-display text-4xl text-ink font-bold mb-8 text-center">השמירות שלי</h1>

      <div className="space-y-12">
        {/* Bookmarks Section */}
        <section>
          <div className="flex items-center gap-2 mb-6 border-b border-gold/30 pb-2">
            <Bookmark className="text-gold-dark" size={24} />
            <h2 className="font-serif text-2xl text-ink font-bold">סימניות ({savedTeachings.length})</h2>
          </div>

          {savedTeachings.length === 0 ? (
            <p className="text-gray-500 font-sans">אין סימניות שמורות.</p>
          ) : (
            <div className="grid gap-4 md:grid-cols-2">
              {savedTeachings.map((item) => (
                <div 
                  key={item.id}
                  className="bg-white p-6 rounded-lg shadow-sm border border-transparent hover:border-gold/30 transition-all group relative"
                >
                  <div 
                    onClick={() => onNavigate(item.chapter, item.teaching.id)}
                    className="cursor-pointer"
                  >
                    <div className="flex justify-between items-start mb-3">
                      <div>
                        <h3 className="font-display text-xl font-bold text-ink">{item.chapter.title}</h3>
                        <span className="text-xs font-sans text-gray-400">{item.part} • אות {item.teaching.letter}</span>
                      </div>
                    </div>
                    <p className="font-serif text-lg text-gray-700 line-clamp-3">
                      {item.teaching.content}
                    </p>
                  </div>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      onRemoveBookmark(item.id);
                    }}
                    className="absolute top-4 left-4 p-2 text-gray-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
                    title="הסר סימניה"
                  >
                    <Bookmark size={18} fill="currentColor" />
                  </button>
                </div>
              ))}
            </div>
          )}
        </section>

