                    className="absolute top-2 left-2 p-1.5 text-gray-400 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 bg-white/80 rounded-full shadow-sm"
                    title="מחק הדגשה"
                  >
                    <XIcon size={16} />
