import React, { useState, useEffect, useRef } from 'react';
import { Chapter, Teaching, Highlight } from '../types';
import { Bookmark, Copy, Highlighter } from 'lucide-react';

interface MiddahViewProps {
  chapter: Chapter;
  bookmarks: string[];
  highlights: Highlight[];
  toggleBookmark: (id: string) => void;
  addHighlight: (teachingId: string, text: string) => void;
  removeHighlight: (id: string) => void;
}

const MiddahView: React.FC<MiddahViewProps> = ({ 
  chapter, 
  bookmarks, 
  highlights,
  toggleBookmark,
  addHighlight,
  removeHighlight
}) => {
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);
  const [selection, setSelection] = useState<{ text: string, top: number, left: number, teachingId: string } | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleSelection = () => {
      const sel = window.getSelection();
      if (!sel || sel.isCollapsed) {
        setSelection(null);
        return;
      }

      const text = sel.toString().trim();
      if (text.length < 2) return;

      // Check if selection is inside a teaching card
      let node = sel.anchorNode;
      while (node && node.nodeType !== Node.ELEMENT_NODE) {
        node = node.parentNode;
      }
      const element = node as HTMLElement;
      const teachingCard = element?.closest('[data-teaching-id]');

      if (teachingCard) {
        const teachingId = teachingCard.getAttribute('data-teaching-id');
        if (teachingId) {
          const range = sel.getRangeAt(0);
          const rect = range.getBoundingClientRect();

          // Adjust for scrolling
          const top = rect.top + window.scrollY - 50;
          const left = rect.left + (rect.width / 2);

          setSelection({
            text,
            top,
            left,
            teachingId
          });
          return;
        }
      }
      setSelection(null);
    };

    document.addEventListener('selectionchange', handleSelection);
    return () => document.removeEventListener('selectionchange', handleSelection);
  }, []);

  // Helper to highlight text
  const renderContentWithHighlights = (content: string, teachingId: string) => {
    const relevantHighlights = highlights.filter(h => h.teachingId === teachingId);
    if (relevantHighlights.length === 0) return content;

    // This is a simplified highlighter that highlights string matches.
    // We sort by length descending to match longest phrases first
    const sortedHighlights = [...relevantHighlights].sort((a, b) => b.text.length - a.text.length);

    // We need to be careful not to double-wrap. 
    // A simple approach for this simplified requirement: split by regex of all highlight texts
    // Create a regex that matches any of the highlight texts
    // Escape regex characters
    const escapeRegExp = (string: string) => string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const pattern = new RegExp(`(${sortedHighlights.map(h => escapeRegExp(h.text)).join('|')})`, 'gi');

    const parts = content.split(pattern);

    return (
      <span>
        {parts.map((part, i) => {
          const highlight = sortedHighlights.find(h => h.text.toLowerCase() === part.toLowerCase());
          if (highlight) {
            return (
              <mark 
                key={i} 
                className="bg-gold/30 text-ink rounded px-0.5 cursor-pointer hover:bg-gold/50 transition-colors"
                title="לחץ להסרה"
                onClick={(e) => {
                  e.stopPropagation();
                  removeHighlight(highlight.id);
                }}
              >
                {part}
              </mark>
            );
          }
          return part;
        })}
      </span>
    );
  };

  const handleCopy = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopyFeedback(id);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  const confirmHighlight = () => {
    if (selection) {
      addHighlight(selection.teachingId, selection.text);
      // Clear selection
      if (window.getSelection) {
        window.getSelection()?.removeAllRanges();
      }
      setSelection(null);
    }
  };

  const renderSection = (title: string, teachings: Teaching[]) => {
    if (!teachings || teachings.length === 0) return null;

    return (
      <div className="mb-12">
        <div className="flex items-center justify-center mb-8">
          <div className="h-px bg-gold/30 flex-1 max-w-xs"></div>
          <h3 className="mx-4 font-display text-2xl text-gold-dark font-bold">{title}</h3>
          <div className="h-px bg-gold/30 flex-1 max-w-xs"></div>
        </div>

        <div className="space-y-6">
          {teachings.map((teaching) => (
            <div 
              key={teaching.id} 
              id={teaching.id}
              data-teaching-id={teaching.id}
              className={`
                group relative bg-white p-6 rounded-lg shadow-sm border border-transparent hover:border-gold/30 transition-all duration-300
                ${bookmarks.includes(teaching.id) ? 'ring-1 ring-gold bg-amber-50/50' : ''}
              `}
            >
              <div className="flex gap-4">
                <span className="font-display text-2xl text-gold-dark w-8 shrink-0">{teaching.letter}.</span>
                <p className="font-serif text-xl leading-relaxed text-ink/90 flex-1 select-text">
                  {renderContentWithHighlights(teaching.content, teaching.id)}
                </p>
              </div>

              {/* Action Buttons */}
              <div className="absolute top-4 left-4 opacity-0 group-hover:opacity-100 transition-opacity flex gap-2">
                <button 
                  onClick={() => toggleBookmark(teaching.id)}
                  className={`p-1.5 rounded-full hover:bg-gray-100 transition-colors ${bookmarks.includes(teaching.id) ? 'text-gold' : 'text-gray-400'}`}
                  title={bookmarks.includes(teaching.id) ? "הסר סימניה" : "שמור סימניה"}
                >
                  <Bookmark size={18} fill={bookmarks.includes(teaching.id) ? "currentColor" : "none"} />
                </button>
                <button 
                  onClick={() => handleCopy(teaching.content, teaching.id)}
                  className="p-1.5 rounded-full hover:bg-gray-100 text-gray-400 hover:text-ink transition-colors relative"
                  title="העתק"
                >
                  {copyFeedback === teaching.id ? (
                    <span className="text-xs font-sans text-green-600 font-bold">הועתק!</span>
                  ) : (
                    <Copy size={18} />
                  )}
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-4xl mx-auto py-8 px-4 md:px-8 relative" ref={containerRef}>

      {/* Highlighting Popover */}
      {selection && (
        <div 
          className="fixed z-50 transform -translate-x-1/2 bg-ink text-paper px-4 py-2 rounded-full shadow-xl flex items-center gap-2 cursor-pointer hover:scale-105 transition-transform animate-bounce"
          style={{ top: selection.top, left: selection.left }}
          onMouseDown={(e) => {
             e.preventDefault(); // Prevent losing selection before click
             confirmHighlight();
          }}
        >
          <Highlighter size={16} />
          <span className="font-sans font-bold text-sm">הדגש</span>
        </div>
      )}

      <header className="text-center mb-12">
        <h1 className="font-display text-5xl md:text-6xl text-ink font-bold mb-4">{chapter.title}</h1>
        {!chapter.isIntroduction && (
          <div className="w-24 h-1 bg-gold mx-auto rounded-full"></div>
        )}
      </header>

      {chapter.isIntroduction ? (
        <article className="prose prose-xl prose-stone max-w-none font-serif leading-relaxed text-justify select-none">
           {chapter.part1.map(t => (
               <p key={t.id} className="whitespace-pre-line mb-6">{t.content}</p>
           ))}
        </article>
      ) : (
        <>
          {renderSection('חלק ראשון', chapter.part1)}
          {renderSection('חלק שני', chapter.part2)}
        </>
      )}
    </div>
  );
};

export default MiddahView;

import React, { useState, useMemo } from 'react';
import { BookData, Chapter } from '../types';
import { Search as SearchIcon } from 'lucide-react';

interface SearchProps {
  data: BookData;
  onNavigate: (chapter: Chapter, teachingId: string) => void;
}

const Search: React.FC<SearchProps> = ({ data, onNavigate }) => {
  const [query, setQuery] = useState('');

  const escapeRegExp = (string: string) => string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

  const results = useMemo(() => {
    if (!query || query.length < 2) return [];

    // Normalize query for search (optional: handle niqqud if text had it, but here text is plain)
    const normalizedQuery = query.trim();
    const res: { chapter: Chapter, content: string, part: string, id: string }[] = [];

    data.chapters.forEach(chapter => {
      // Search in title
      if (chapter.title.includes(normalizedQuery)) {
        res.push({ 
            chapter, 
            content: `פרק: ${chapter.title}`, 
            part: 'כותרת', 
            id: `title-${chapter.title}` 
        });
      }

      // Search in Part 1
      chapter.part1.forEach(t => {
        if (t.content.includes(normalizedQuery)) {
          res.push({ chapter, content: t.content, part: 'חלק ראשון', id: t.id });
        }
      });

      // Search in Part 2
      chapter.part2.forEach(t => {
        if (t.content.includes(normalizedQuery)) {
          res.push({ chapter, content: t.content, part: 'חלק שני', id: t.id });
        }
      });
    });

    return res;
  }, [query, data]);

  const highlightText = (text: string, highlight: string) => {
    if (!highlight) return text;

    // Use Regex for case-insensitive (though Hebrew is single case) global match
    const escapedHighlight = escapeRegExp(highlight);
    const parts = text.split(new RegExp(`(${escapedHighlight})`, 'gi'));

    return (
      <span>
        {parts.map((part, i) => 
          part.toLowerCase() === highlight.toLowerCase() ? (
            <span key={i} className="bg-gold/40 font-bold px-0.5 rounded text-ink">{part}</span>
          ) : part
        )}
      </span>
    );
  };

  return (
    <div className="max-w-4xl mx-auto py-8 px-4">
      <div className="relative mb-8">
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="חפש נושא, מילה או משפט..."
          className="w-full p-4 pr-12 rounded-xl border-2 border-gold/30 focus:border-gold outline-none font-sans text-lg shadow-sm bg-white"
          autoFocus
        />
        <SearchIcon className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400" size={24} />
      </div>

      <div className="space-y-4">
        {query.length > 1 && results.length === 0 && (
          <p className="text-center text-gray-500 font-sans mt-8">לא נמצאו תוצאות עבור "{query}"</p>
        )}

        {results.map((result) => (
          <div 
            key={result.id}
            onClick={() => onNavigate(result.chapter, result.id)}
            className="bg-white p-4 rounded-lg shadow-sm border border-transparent hover:border-gold/30 cursor-pointer transition-all hover:bg-amber-50/30"
          >
            <div className="flex justify-between items-center mb-2">
              <h3 className="font-display text-xl font-bold text-ink">{result.chapter.title}</h3>
              <span className="text-xs font-sans text-gold-dark bg-gold/10 px-2 py-1 rounded-full">
                {result.part}
              </span>
            </div>
            <p className="font-serif text-lg text-gray-700 leading-relaxed truncate">
              {highlightText(result.content, query)}
            </p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Search;

import React, { useState, useEffect, useMemo } from 'react';
import { Menu, Search as SearchIcon, Home, Book, Bookmark as BookmarkIcon, Shuffle } from 'lucide-react';
import Sidebar from './components/Sidebar';
import MiddahView from './components/MiddahView';
import Welcome from './components/Welcome';
import Search from './components/Search';
import BookmarksView from './components/BookmarksView';
import RandomView from './components/RandomView';
import { parseText } from './services/textParser';
import { BookData, Chapter, ViewMode, Highlight } from './types';

const App: React.FC = () => {
  const [data, setData] = useState<BookData | null>(null);
  const [currentChapter, setCurrentChapter] = useState<Chapter | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.HOME);
  const [bookmarks, setBookmarks] = useState<string[]>([]);
  const [highlights, setHighlights] = useState<Highlight[]>([]);

  useEffect(() => {
    // Parse text on mount
    const parsedData = parseText();
    setData(parsedData);

    // Load persisted data
    const savedBookmarks = localStorage.getItem('seferBookmarks');
    if (savedBookmarks) {
      setBookmarks(JSON.parse(savedBookmarks));
    }
    const savedHighlights = localStorage.getItem('seferHighlights');
    if (savedHighlights) {
        setHighlights(JSON.parse(savedHighlights));
    }
  }, []);

  const toggleBookmark = (id: string) => {
    const newBookmarks = bookmarks.includes(id)
      ? bookmarks.filter(b => b !== id)
      : [...bookmarks, id];
    setBookmarks(newBookmarks);
    localStorage.setItem('seferBookmarks', JSON.stringify(newBookmarks));
  };

  const addHighlight = (teachingId: string, text: string) => {
    const newHighlight: Highlight = {
        id: Date.now().toString(),
        teachingId,
        text,
        date: Date.now()
    };
    const newHighlights = [...highlights, newHighlight];
    setHighlights(newHighlights);
    localStorage.setItem('seferHighlights', JSON.stringify(newHighlights));
  };

  const removeHighlight = (id: string) => {
    const newHighlights = highlights.filter(h => h.id !== id);
    setHighlights(newHighlights);
    localStorage.setItem('seferHighlights', JSON.stringify(newHighlights));
  };

  const handleChapterSelect = (chapter: Chapter, teachingId?: string) => {
    setCurrentChapter(chapter);
    setViewMode(ViewMode.READING);
    setSidebarOpen(false);

    if (teachingId) {
      // Small delay to allow render before scrolling
      setTimeout(() => {
        const el = document.getElementById(teachingId);
        if (el) el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 100);
    } else {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const mainContent = useMemo(() => {
    if (!data) return <div className="flex justify-center items-center h-full">טוען...</div>;

    switch (viewMode) {
      case ViewMode.HOME:
        return <Welcome data={data} onStart={() => setSidebarOpen(true)} />;
      case ViewMode.SEARCH:
        return <Search data={data} onNavigate={handleChapterSelect} />;
      case ViewMode.BOOKMARKS:
        return (
          <BookmarksView 
            data={data} 
            bookmarks={bookmarks} 
            highlights={highlights}
            onNavigate={handleChapterSelect} 
            onRemoveBookmark={(id) => toggleBookmark(id)}
            onRemoveHighlight={removeHighlight}
          />
        );
      case ViewMode.RANDOM:
          return <RandomView data={data} onNavigate={handleChapterSelect} />;
      case ViewMode.READING:
        if (currentChapter) {
          return (
            <MiddahView 
              chapter={currentChapter} 
              bookmarks={bookmarks} 
              highlights={highlights}
              toggleBookmark={toggleBookmark} 
              addHighlight={addHighlight}
              removeHighlight={removeHighlight}
            />
          );
        }
        return <Welcome data={data} onStart={() => setSidebarOpen(true)} />; // Fallback
      default:
        return null;
    }
  }, [viewMode, data, currentChapter, bookmarks, highlights]);

  if (!data) return null;

  return (
    <div className="flex h-screen bg-paper overflow-hidden">

      {/* Sidebar */}
      <Sidebar 
        chapters={data.chapters}
        currentChapter={currentChapter}
        onSelectChapter={(c) => handleChapterSelect(c)}
        isOpen={sidebarOpen}
        onClose={() => setSidebarOpen(false)}
      />

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0">

        {/* Top Bar */}
        <header className="h-16 bg-paper-dark border-b border-gold/30 flex items-center justify-between px-4 md:px-8 shadow-sm z-30">
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setSidebarOpen(true)}
              className="md:hidden text-ink hover:text-gold-dark p-2"
            >
              <Menu size={24} />
            </button>
            <span className="font-display text-2xl font-bold text-ink hidden md:block">ספר המידות</span>
          </div>

          <div className="flex items-center gap-2 md:gap-4 overflow-x-auto no-scrollbar">
            <button 
              onClick={() => setViewMode(ViewMode.HOME)}
              className={`p-2 rounded-full transition-colors ${viewMode === ViewMode.HOME ? 'text-gold-dark bg-gold/10' : 'text-gray-500 hover:bg-black/5'}`}
              title="דף הבית"
            >
              <Home size={20} />
            </button>
            <button 
              onClick={() => setViewMode(ViewMode.SEARCH)}
              className={`p-2 rounded-full transition-colors ${viewMode === ViewMode.SEARCH ? 'text-gold-dark bg-gold/10' : 'text-gray-500 hover:bg-black/5'}`}
              title="חיפוש"
            >
              <SearchIcon size={20} />
            </button>
            <button 
              onClick={() => setViewMode(ViewMode.BOOKMARKS)}
              className={`p-2 rounded-full transition-colors ${viewMode === ViewMode.BOOKMARKS ? 'text-gold-dark bg-gold/10' : 'text-gray-500 hover:bg-black/5'}`}
              title="סימניות והדגשות"
            >
              <BookmarkIcon size={20} />
            </button>
            <button 
              onClick={() => setViewMode(ViewMode.RANDOM)}
              className={`p-2 rounded-full transition-colors ${viewMode === ViewMode.RANDOM ? 'text-gold-dark bg-gold/10' : 'text-gray-500 hover:bg-black/5'}`}
              title="לימוד אקראי"
            >
              <Shuffle size={20} />
            </button>
          </div>
        </header>

        {/* Scrollable Content */}
        <main className="flex-1 overflow-y-auto relative scroll-smooth">
          {mainContent}
        </main>

      </div>
    </div>
  );
};

export default App;
